    return (
        <div className="pt-20 px-6 h-full overflow-y-auto pb-32 max-w-6xl mx-auto">
            {/* Header / Stats */}
            <div className="flex flex-col md:flex-row justify-between items-center mb-10 gap-4">
                <div className="text-right">
                    <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">חנות הרקעים</h2>
                    <p className="text-dogame-muted">שדרג את הפרופיל שלך עם רקעים נדירים</p>
                </div>
                <div className="bg-dogame-surface px-6 py-3 rounded-2xl border border-white/10 flex items-center gap-3 shadow-glow">
                    <span className="text-2xl font-bold text-white">{userCoins}</span>
                    <i className="fa-solid fa-coins text-yellow-400 text-xl"></i>
                    <span className="text-dogame-muted mr-2">היתרה שלך</span>
                </div>
            </div>

            {/* Preview Banner (If item selected) */}
            {previewItem && (
                <div className="mb-10 animate-pop">
                    <h3 className="text-sm font-bold text-dogame-muted mb-2 text-right">תצוגה מקדימה</h3>
                    <div className="relative h-40 w-full rounded-2xl overflow-hidden border-2 border-dogame-primary shadow-glow">
                        <img 
                            src={previewItem.previewUrl} 
                            className={`w-full h-full object-cover ${previewItem.animationClass || ''}`} 
                            alt="preview"
                        />
                        <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent"></div>
                        <div className="absolute bottom-4 right-6 text-white text-right">
                            <span className="text-xs font-bold uppercase tracking-widest block opacity-70">פרופיל של ישראל</span>
                            <h4 className="text-xl font-bold">{previewItem.name}</h4>
                        </div>
                        <button 
                            onClick={() => setPreviewItem(null)}
                            className="absolute top-4 left-4 w-8 h-8 bg-black/50 rounded-full flex items-center justify-center text-white hover:bg-black/80 transition-colors"
                        >
                            <i className="fa-solid fa-xmark"></i>
                        </button>
                    </div>
                </div>
            )}

            {/* Shop Grid */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                {backgroundShopItems.map((item) => (
                    <div 
                        key={item.id} 
                        className="bg-dogame-surface rounded-3xl overflow-hidden border border-white/5 group hover:border-white/20 transition-all flex flex-col"
                    >
                        {/* Image Container */}
                        <div className="relative aspect-video overflow-hidden">
                            <img 
                                src={item.previewUrl} 
                                className={`w-full h-full object-cover transition-transform duration-700 group-hover:scale-110 ${item.isAnimated ? item.animationClass : ''}`}
                                alt={item.name} 
                            />
                            {item.isAnimated && (
                                <div className="absolute top-3 left-3 bg-dogame-primary/80 backdrop-blur-md px-2 py-1 rounded-lg text-[10px] font-bold text-white flex items-center gap-1">
                                    <i className="fa-solid fa-wand-magic-sparkles animate-pulse"></i>
                                    <span>LIVE</span>
                                </div>
