                            <div className={`absolute top-3 right-3 px-3 py-1 rounded-full text-[10px] font-bold border ${getRarityColor(item.rarity)}`}>
                                {item.rarity}
                            </div>
                        </div>

                        {/* Details */}
                        <div className="p-5 flex-1 flex flex-col">
                            <div className="flex justify-between items-start mb-4">
                                <div className="text-right">
                                    <h4 className="text-white font-bold text-lg">{item.name}</h4>
                                    <div className="flex items-center justify-end gap-1 mt-1">
                                        <span className="text-yellow-400 font-bold">{item.price}</span>
                                        <i className="fa-solid fa-coins text-[10px] text-yellow-400"></i>
                                    </div>
                                </div>
                                <button 
                                    onClick={() => setPreviewItem(item)}
                                    className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center text-dogame-muted hover:text-white hover:bg-white/10 transition-colors"
