                {games.map(g => (
                    <button key={g.name} onClick={() => onSelect(g.name)} className="bg-dogame-surface/60 backdrop-blur-md rounded-2xl p-4 flex items-center gap-4 hover:bg-white/5 transition-colors text-right shadow-sm group">
                        <div className={`w-12 h-12 rounded-xl ${g.color} flex items-center justify-center shadow-lg`}>
                             <i className={`fa-solid ${g.icon} text-white text-xl`}></i>
