const App: React.FC = () => {
    const [activeView, setActiveView] = useState<ActiveView>('swipe');
    const [viewingProfile, setViewingProfile] = useState<GamerProfile | null>(null);
    const [likedProfiles, setLikedProfiles] = useState<GamerProfile[]>([]);
    const [userProfile, setUserProfile] = useState<GamerProfile>(currentUserProfile);
    const [isSubModalOpen, setIsSubModalOpen] = useState(false);
    const [gameFilter, setGameFilter] = useState<string | null>(null);
    const [userCoins, setUserCoins] = useState(1200);
    const [globalBackground, setGlobalBackground] = useState<string | null>(null);

    const handleNavigate = (view: ActiveView) => {
        setActiveView(view);
        setViewingProfile(null);
    };

    const handlePurchase = (item: BackgroundItem) => {
        if (userCoins >= item.price) {
            setUserCoins(prev => prev - item.price);
            setUserProfile(prev => ({...prev, bannerImage: item.previewUrl}));
            alert(`תתחדש! הרקע "${item.name}" נרכש והופעל בפרופיל שלך.`);
        } else {
            alert('אין לך מספיק מטבעות!');
        }
    };

    const handleSetGlobalBackground = (url: string | undefined) => {
        setGlobalBackground(url || null);
    };

    return (
        <div className="h-screen w-full relative bg-dogame-bg text-dogame-text font-sans overflow-hidden">
            {/* Global Background Layer */}
            {globalBackground && (
                <div className="fixed inset-0 z-0 overflow-hidden">
                    <img 
                        src={globalBackground} 
                        className="w-full h-full object-cover opacity-30 blur-[2px] scale-105" 
                        alt="Global background"
                    />
                    <div className="absolute inset-0 bg-gradient-to-b from-dogame-bg/40 via-dogame-bg/80 to-dogame-bg"></div>
                </div>
            )}

            <SideNav activeView={activeView} onNavigate={handleNavigate} />

            <div className="h-full w-full mr-[72px] flex flex-col transition-all duration-300 relative z-10">
                <Header 
                    viewTitle={activeView} 
                    onOpenSubscriptions={() => setIsSubModalOpen(true)}
                    onOpenProfile={() => { setViewingProfile(null); setActiveView('profile'); }}
                    onOpenChat={() => setActiveView('chat')}
                    showBackButton={activeView !== 'swipe'}
                    onBack={() => handleNavigate('swipe')}
                />

                <main className="flex-1 w-full overflow-hidden relative">
                    {activeView === 'swipe' && <SwipeView onLike={(p) => setLikedProfiles([...likedProfiles, p])} userProfile={userProfile} gameFilter={gameFilter} onClearFilter={() => setGameFilter(null)} />}
                    {activeView === 'search' && <SearchView onSelect={(g) => { setGameFilter(g); setActiveView('swipe'); }} />}
                    {activeView === 'shop' && <ShopView onPurchase={handlePurchase} userCoins={userCoins} />}
                    {activeView === 'likes-you' && <LikesGrid profiles={profilesWhoLikedUser} onProfileClick={(p) => {setViewingProfile(p); setActiveView('profile');}} />}
                    {activeView === 'chat' && <ChatView matches={matchedProfiles} onBack={() => setActiveView('swipe')} />}
                    {activeView === 'profile' && (
                        <ProfileView 
                            profile={viewingProfile || userProfile} 
                            onSave={setUserProfile} 
                            isOwnProfile={!viewingProfile} 
                            onReturnToLobby={() => setActiveView('swipe')}
                            isGlobalBackground={globalBackground === (viewingProfile?.bannerImage || userProfile.bannerImage)}
                            onSetGlobalBackground={handleSetGlobalBackground}
                        />
                    )}
                </main>
            </div>
        </div>
    );
};

export default App;

