const SwipeView: React.FC<{ onLike: (p: GamerProfile) => void; userProfile: GamerProfile; gameFilter: string | null; onClearFilter: () => void }> = ({ onLike, userProfile, gameFilter, onClearFilter }) => {
    const filteredProfiles = useMemo(() => gameFilter ? gamerProfiles.filter(p => p.games.some(g => g.name === gameFilter)) : gamerProfiles, [gameFilter]);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [swipedDirection, setSwipedDirection] = useState<'left' | 'right' | null>(null);
    const [showMatch, setShowMatch] = useState(false);
    const [matchedProfile, setMatchedProfile] = useState<GamerProfile | null>(null);

    const activeProfile = filteredProfiles[currentIndex];

    const handleSwipe = (direction: 'left' | 'right') => {
        if (!activeProfile) return;
        setSwipedDirection(direction);
        setTimeout(() => {
            if (direction === 'right') {
                onLike(activeProfile);
                if (Math.random() > 0.6) {
                    setMatchedProfile(activeProfile);
                    setShowMatch(true);
                }
            }
            setCurrentIndex(prev => prev + 1);
            setSwipedDirection(null);
        }, 300);
    };

    if (!activeProfile) return (
        <div className="flex flex-col items-center justify-center h-full text-center p-8 relative z-10">
            <h2 className="text-2xl font-bold dark:text-white text-dogame-lightText mb-2">זה הכל להיום!</h2>
            <button onClick={() => setCurrentIndex(0)} className="px-8 py-3 bg-dogame-primary text-white font-bold rounded-full shadow-glow">
                התחל מחדש
            </button>
        </div>
    );

    return (
        <div className="h-full w-full relative flex flex-col items-center justify-center pb-10 pt-16 px-4 max-w-xl mx-auto z-10">
             {showMatch && matchedProfile && (
                <div className="fixed inset-0 z-[100] dark:bg-dogame-bg/95 bg-white/95 backdrop-blur-md flex flex-col items-center justify-center p-6 animate-pop">
                    <h1 className="text-4xl font-bold dark:text-white text-dogame-lightText mb-2">יש התאמה!</h1>
                    <button onClick={() => setShowMatch(false)} className="w-full py-4 bg-dogame-primary text-white rounded-xl font-bold text-lg shadow-glow mt-8">
                        מעולה!
                    </button>
                </div>
            )}

            <div className="relative w-full aspect-[3/4.5] max-h-[60vh]">
                <div 
                    className={`absolute inset-0 dark:bg-dogame-surface/60 bg-white/60 backdrop-blur-md rounded-3xl overflow-hidden shadow-2xl border dark:border-white/5 border-gray-200 transition-transform duration-300 ease-out ${swipedDirection === 'left' ? '-translate-x-[150%] -rotate-12' : swipedDirection === 'right' ? 'translate-x-[150%] rotate-12' : ''}`}
                >
                    <img src={activeProfile.image} className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/20 to-transparent"></div>
                    <div className="absolute bottom-0 w-full p-6 text-right">
                        <h2 className="text-3xl font-bold text-white">{activeProfile.name}, {activeProfile.age}</h2>
                    </div>
                </div>
            </div>

            <div className="absolute bottom-4 w-full max-w-xs flex justify-center gap-8 px-4">
                <button onClick={() => handleSwipe('left')} className="w-16 h-16 rounded-full dark:bg-dogame-surface/80 bg-white/80 backdrop-blur-md border border-dogame-danger/30 text-dogame-danger text-2xl flex items-center justify-center shadow-soft">
                    <i className="fa-solid fa-xmark"></i>
                </button>
                 <button onClick={() => handleSwipe('right')} className="w-16 h-16 rounded-full bg-dogame-primary text-white text-2xl flex items-center justify-center shadow-glow">
                    <i className="fa-solid fa-heart"></i>
                </button>
            </div>
        </div>
    );
};

const App: React.FC = () => {
    const [activeView, setActiveView] = useState<ActiveView>('swipe');
    const [viewingProfile, setViewingProfile] = useState<GamerProfile | null>(null);
    const [likedProfiles, setLikedProfiles] = useState<GamerProfile[]>([]);
    const [userProfile, setUserProfile] = useState<GamerProfile>(currentUserProfile);
    const [isDarkMode, setIsDarkMode] = useState(true);
    const [userCoins, setUserCoins] = useState(1200);
    const [globalBackground, setGlobalBackground] = useState<string | null>(null);
    const [isGlobalBgEnabled, setIsGlobalBgEnabled] = useState(true);

    useEffect(() => {
        document.body.className = isDarkMode ? 'dark overflow-hidden' : 'light overflow-hidden';
    }, [isDarkMode]);

    const handleNavigate = (view: ActiveView) => {
        setActiveView(view);
        setViewingProfile(null);
    };

    const handlePurchase = (item: BackgroundItem) => {
        if (userCoins >= item.price) {
            setUserCoins(prev => prev - item.price);
            const newItem = {...item};
            setUserProfile(prev => ({...prev, bannerImage: newItem.previewUrl}));
            // Automatically set as global if it's currently enabled
            if (isGlobalBgEnabled) setGlobalBackground(newItem.previewUrl);
            alert(`תתחדש! הרקע "${item.name}" נרכש והופעל.`);
        } else {
            alert('אין לך מספיק מטבעות!');
        }
    };

    const displayBackground = isGlobalBgEnabled ? (globalBackground || userProfile.bannerImage) : (activeView === 'profile' ? (viewingProfile?.bannerImage || userProfile.bannerImage) : null);

    return (
        <div className={`h-screen w-full relative font-sans overflow-hidden transition-colors duration-300 ${isDarkMode ? 'bg-dogame-bg text-dogame-text' : 'bg-dogame-lightBg text-dogame-lightText'}`}>

            {/* Background Layer */}
            {displayBackground && (
                <div className="fixed inset-0 z-0 overflow-hidden pointer-events-none">
                    <img 
                        src={displayBackground} 
                        className="w-full h-full object-cover opacity-30 blur-[2px] scale-105 bg-moving" 
                        alt="Background layer"
                    />
                    <div className={`absolute inset-0 bg-gradient-to-b ${isDarkMode ? 'from-dogame-bg/40 via-dogame-bg/80 to-dogame-bg' : 'from-dogame-lightBg/40 via-dogame-lightBg/80 to-dogame-lightBg'}`}></div>
                </div>
            )}

            <SideNav activeView={activeView} onNavigate={handleNavigate} />

            <div className="h-full w-full mr-[72px] flex flex-col transition-all duration-300 relative z-10">
                <Header 
                    viewTitle={activeView} 
                    onOpenSubscriptions={() => {}}
                    onOpenProfile={() => { setViewingProfile(null); setActiveView('profile'); }}
                    onOpenChat={() => setActiveView('chat')}
                    showBackButton={activeView !== 'swipe'}
                    onBack={() => handleNavigate('swipe')}
                />

                <main className="flex-1 w-full overflow-hidden relative">
                    {activeView === 'swipe' && <SwipeView onLike={(p) => setLikedProfiles([...likedProfiles, p])} userProfile={userProfile} gameFilter={null} onClearFilter={() => {}} />}
                    {activeView === 'search' && <div className="p-20 text-center dark:text-white">חיפוש בקרוב...</div>}
                    {activeView === 'shop' && <ShopView onPurchase={handlePurchase} userCoins={userCoins} />}
                    {activeView === 'likes-you' && <LikesGrid profiles={profilesWhoLikedUser} onProfileClick={(p) => {setViewingProfile(p); setActiveView('profile');}} />}
                    {activeView === 'chat' && <ChatView matches={matchedProfiles} onBack={() => setActiveView('swipe')} />}
                    {activeView === 'settings' && (
                        <SettingsView 
                            isDarkMode={isDarkMode} 
                            onToggleTheme={() => setIsDarkMode(!isDarkMode)} 
                            isGlobalBgEnabled={isGlobalBgEnabled}
                            onToggleGlobalBg={() => setIsGlobalBgEnabled(!isGlobalBgEnabled)}
                        />
                    )}
                    {activeView === 'profile' && (
                        <ProfileView 
                            profile={viewingProfile || userProfile} 
                            onSave={setUserProfile} 
                            isOwnProfile={!viewingProfile} 
                            onReturnToLobby={() => setActiveView('swipe')}
                            isGlobalBackground={globalBackground === (viewingProfile?.bannerImage || userProfile.bannerImage)}
                            onSetGlobalBackground={(url) => setGlobalBackground(url || null)}
                        />
                    )}
                </main>
            </div>
        </div>
    );
};

export default App;

