                    </div>
                )}

                {/* Main Card */}
                <div className="bg-dogame-surface/40 backdrop-blur-2xl rounded-[32px] p-8 shadow-2xl border border-white/10 mb-8">
                    <div className="flex justify-between items-center mb-6">
                        <h3 className="text-xl font-black text-white italic uppercase">ביוגרפיה</h3>
                        {isOwnProfile && !isEditing && (
                             <button onClick={() => setIsEditing(true)} className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center text-dogame-primary hover:bg-dogame-primary hover:text-white transition-all shadow-sm">
                                <i className="fa-solid fa-pen-to-square"></i>
                             </button>
                        )}
                    </div>

                    {isEditing ? (
                        <textarea value={editedProfile.bio} onChange={e => setEditedProfile({...editedProfile, bio: e.target.value})} className="w-full bg-black/20 border border-white/10 rounded-2xl p-4 text-white focus:outline-none focus:border-dogame-primary min-h-[150px]" />
                    ) : (
                        <p className="text-gray-200 leading-relaxed text-right text-lg">
                            {editedProfile.bio}
                        </p>
                    )}

                    {isOwnProfile && isEditing && (
                        <div className="grid grid-cols-2 gap-4 mt-8">
                            <button onClick={handleSave} className="py-4 bg-dogame-primary text-white rounded-2xl font-black italic uppercase shadow-glow hover:scale-[1.02] transition-transform">שמור שינויים</button>
                            <button onClick={() => setIsEditing(false)} className="py-4 bg-white/5 text-white rounded-2xl font-black italic uppercase border border-white/10 hover:bg-white/10 transition-colors">ביטול</button>
                        </div>
                    )}
                </div>

                {/* Stats / Info */}
                <div className="grid grid-cols-2 gap-6 mb-8">
                     <div className="bg-white/5 backdrop-blur-lg p-6 rounded-[24px] border border-white/10 text-center shadow-lg">
                         <span className="text-dogame-muted text-xs font-black uppercase tracking-widest block mb-2">רמת מיומנות</span>
                         <span className="text-2xl font-black text-white italic uppercase">{profile.skillLevel}</span>
                     </div>
                     <div className="bg-white/5 backdrop-blur-lg p-6 rounded-[24px] border border-white/10 text-center shadow-lg">
                         <span className="text-dogame-muted text-xs font-black uppercase tracking-widest block mb-2">ספריית משחקים</span>
                         <span className="text-2xl font-black text-white italic uppercase">{profile.games.length} פריטים</span>
                     </div>
                </div>

                {/* Games List */}
                <div className="mb-12">
                    <h3 className="text-xl font-black text-white mb-6 text-right px-1 italic uppercase tracking-tighter">התמחות בגיימינג</h3>
                    <div className="space-y-4">
                        {editedProfile.games.map((game, idx) => (
                            <div key={idx} className="bg-dogame-surface/30 backdrop-blur-xl p-6 rounded-[24px] border border-white/10 flex items-start gap-5 hover:bg-white/5 transition-all text-right shadow-xl group">
                                <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-dogame-primary/20 to-dogame-accent/20 flex items-center justify-center shrink-0 border border-white/10 group-hover:rotate-6 transition-transform">
                                    <i className={`fa-solid ${game.icon} text-dogame-primary text-2xl`}></i>
                                </div>
                                <div className="flex-1">
                                    <h4 className="font-black text-white text-lg italic uppercase">{game.name}</h4>
                                    <p className="text-gray-400 mt-2 leading-snug">{game.lookingFor}</p>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Actions Only */}
                {isOwnProfile && !isEditing && (
                    <div className="flex flex-col gap-4 mb-12">
                        <button 
                            onClick={() => setIsCollectionModalOpen(true)}
                            className="w-full py-4 bg-gradient-to-r from-dogame-primary to-dogame-accent text-white font-black italic uppercase rounded-[20px] shadow-glow hover:scale-[1.01] transition-all flex items-center justify-center gap-3"
                        >
                            <i className="fa-solid fa-palette"></i>
                            <span>שנה רקע פרופיל מהאוסף</span>
                        </button>
                        <button className="w-full py-4 text-dogame-danger font-black italic uppercase hover:bg-dogame-danger/10 rounded-[20px] transition-colors border border-dogame-danger/10">
                            התנתק מהמערכת
                        </button>
                    </div>
                )}
            </div>
        </div>
    );
};

export default ProfileView;

import React, { useState, useMemo } from 'react';
import { backgroundShopItems } from '../constants';
import { BackgroundItem } from '../types';

interface ShopViewProps {
    onPurchase: (item: BackgroundItem) => void;
    userCoins: number;
    ownedItems: BackgroundItem[];
}

type Category = 'All' | 'Cyber' | 'Space' | 'Nature' | 'Abstract';

const ShopView: React.FC<ShopViewProps> = ({ onPurchase, userCoins, ownedItems }) => {
    const [previewItem, setPreviewItem] = useState<BackgroundItem | null>(null);
    const [selectedCategory, setSelectedCategory] = useState<Category>('All');

    const filteredItems = useMemo(() => {
        if (selectedCategory === 'All') return backgroundShopItems;
        return backgroundShopItems.filter(item => item.category === selectedCategory);
    }, [selectedCategory]);

    const isOwned = (id: string) => ownedItems.some(item => item.id === id);

    const getRarityStyles = (rarity: BackgroundItem['rarity']) => {
        switch (rarity) {
            case 'Legendary': return 'text-yellow-400 border-yellow-500/50 bg-yellow-500/10 shadow-[0_0_15px_rgba(234,179,8,0.3)]';
            case 'Epic': return 'text-purple-400 border-purple-500/50 bg-purple-500/10 shadow-[0_0_15px_rgba(168,85,247,0.3)]';
            case 'Rare': return 'text-blue-400 border-blue-500/50 bg-blue-500/10';
            default: return 'text-gray-400 border-gray-500/50 bg-gray-500/10';
        }
    };

    const categories: Category[] = ['All', 'Cyber', 'Space', 'Nature', 'Abstract'];

    return (
        <div className="relative h-full w-full overflow-hidden">
            {/* Full Screen Live Preview Background */}
            {previewItem && (
                <div 
                    className={`absolute inset-0 z-0 transition-all duration-1000 opacity-30 pointer-events-none ${previewItem.isAnimated ? previewItem.animationClass : ''}`}
                    style={{ background: previewItem.previewUrl }}
                />
            )}

            <div className="relative z-10 pt-24 px-6 h-full overflow-y-auto pb-32 max-w-7xl mx-auto no-scrollbar">
                {/* Top Bar: Stats & Welcome */}
                <div className="flex flex-col lg:flex-row justify-between items-end mb-12 gap-6">
                    <div className="text-right w-full lg:w-auto">
                        <h2 className="text-4xl font-black text-white italic uppercase tracking-tighter mb-2">חנות הצבעים</h2>
                        <p className="text-dogame-muted text-lg">בחר את האווירה שלך עם צבעים וגרדיאנטים ייחודיים</p>
                    </div>

                    <div className="flex items-center gap-6 w-full lg:w-auto justify-between lg:justify-end">
                        {/* Category Selector */}
                        <div className="flex bg-dogame-surface/50 p-1.5 rounded-2xl border border-white/5 backdrop-blur-md overflow-x-auto no-scrollbar">
                            {categories.map(cat => (
                                <button
                                    key={cat}
                                    onClick={() => setSelectedCategory(cat)}
                                    className={`px-5 py-2 rounded-xl text-sm font-bold transition-all whitespace-nowrap ${
                                        selectedCategory === cat 
                                        ? 'bg-dogame-primary text-white shadow-glow' 
                                        : 'text-dogame-muted hover:text-white'
                                    }`}
                                >
                                    {cat === 'All' ? 'הכל' : cat}
                                </button>
                            ))}
                        </div>

                        {/* Coins Display */}
                        <div className="bg-gradient-to-br from-dogame-surface to-dogame-bg px-6 py-3 rounded-2xl border border-white/10 flex items-center gap-3 shadow-xl shrink-0">
                            <div className="flex flex-col items-end">
                                <span className="text-xs text-dogame-muted font-bold uppercase tracking-widest">יתרה</span>
                                <span className="text-2xl font-black text-white leading-none">{userCoins.toLocaleString()}</span>
                            </div>
                            <i className="fa-solid fa-coins text-yellow-400 text-2xl drop-shadow-[0_0_8px_rgba(234,179,8,0.5)]"></i>
                        </div>
                    </div>
                </div>

                {/* Status Message for Preview */}
                {previewItem && (
                    <div className="mb-8 animate-pop text-center bg-white/5 backdrop-blur-md py-4 rounded-2xl border border-white/10">
                        <p className="text-white font-black italic uppercase text-lg tracking-wider">
                            <span className="text-dogame-primary ml-2">מציג כעת:</span>
                            {previewItem.name}
                        </p>
                        <button 
                            onClick={() => setPreviewItem(null)}
                            className="mt-2 text-xs font-bold text-dogame-danger hover:underline uppercase"
                        >
                            בטל תצוגה מקדימה
                        </button>
                    </div>
                )}

                {/* Shop Grid */}
                <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
                    {filteredItems.map((item) => {
                        const owned = isOwned(item.id);
                        const isBeingPreviewed = previewItem?.id === item.id;

                        return (
                            <div 
                                key={item.id} 
                                className={`group relative bg-dogame-surface/40 backdrop-blur-sm rounded-[32px] overflow-hidden border transition-all duration-500 shadow-xl flex flex-col ${
                                    isBeingPreviewed ? 'border-dogame-primary scale-[1.02] shadow-glow' : 'border-white/5 hover:border-dogame-primary/50'
                                }`}
                            >
                                {/* Color Swatch Section */}
                                <div className="relative aspect-[16/9] overflow-hidden cursor-pointer" onClick={() => setPreviewItem(item)}>
                                    <div 
                                        style={{ background: item.previewUrl }}
                                        className={`w-full h-full transition-transform duration-1000 group-hover:scale-110 ${item.isAnimated ? item.animationClass : ''}`}
                                    />

                                    {/* Overlays */}
                                    <div className="absolute inset-0 bg-gradient-to-t from-dogame-surface/40 via-transparent to-transparent opacity-60"></div>

                                    {/* Badge: Live vs Static */}
                                    <div className={`absolute top-4 left-4 px-3 py-1 rounded-full text-[9px] font-black text-white flex items-center gap-1.5 shadow-lg border border-white/10 ${item.isAnimated ? 'bg-indigo-600' : 'bg-gray-700'}`}>
                                        {item.isAnimated ? (
                                            <>
                                                <span className="relative flex h-2 w-2">
                                                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-white opacity-75"></span>
                                                    <span className="relative inline-flex rounded-full h-2 w-2 bg-white"></span>
                                                </span>
                                                צבע דינמי
                                            </>
                                        ) : (
                                            <>
                                                <i className="fa-solid fa-palette text-[10px]"></i>
                                                צבע סטטי
                                            </>
                                        )}
                                    </div>

                                    {/* Badge: Rarity */}
                                    <div className={`absolute top-4 right-4 px-4 py-1 rounded-full text-[10px] font-black border backdrop-blur-md ${getRarityStyles(item.rarity)}`}>
                                        {item.rarity.toUpperCase()}
                                    </div>

                                    {/* Try On Overlay */}
                                    <div className={`absolute inset-0 bg-dogame-primary/20 flex items-center justify-center transition-opacity duration-300 ${isBeingPreviewed ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}>
                                        <div className="bg-white text-dogame-bg font-black px-6 py-2 rounded-full transform transition-transform">
                                            {isBeingPreviewed ? 'בתצוגה מקדימה' : 'נסה על המסך'}
                                        </div>
                                    </div>
                                </div>

                                {/* Info Section */}
                                <div className="p-6 flex-1 flex flex-col bg-gradient-to-b from-transparent to-black/20">
                                    <div className="flex justify-between items-start mb-6">
                                        <div className="text-right">
                                            <h4 className="text-white font-black text-xl italic uppercase tracking-tight">{item.name}</h4>
                                            <span className="text-dogame-muted text-xs font-bold">{item.category} Palette</span>
                                        </div>
                                        <div className="flex items-center gap-1.5 bg-white/5 px-3 py-1 rounded-lg">
                                            <span className="text-yellow-400 font-black text-lg leading-none">{item.price.toLocaleString()}</span>
                                            <i className="fa-solid fa-coins text-xs text-yellow-400"></i>
                                        </div>
                                    </div>

                                    <button 
                                        onClick={() => !owned && onPurchase(item)}
                                        className={`w-full py-4 rounded-2xl font-black text-lg transition-all active:scale-95 shadow-lg flex items-center justify-center gap-3 ${
                                            owned 
                                            ? 'bg-dogame-success/20 text-dogame-success border border-dogame-success/30 cursor-default'
                                            : userCoins >= item.price
                                            ? 'bg-white text-dogame-bg hover:bg-dogame-primary hover:text-white'
                                            : 'bg-white/5 text-dogame-muted cursor-not-allowed border border-white/10'
                                        }`}
                                        disabled={!owned && userCoins < item.price}
                                    >
                                        {owned ? (
                                            <>
                                                <span>כבר בבעלותך</span>
                                                <i className="fa-solid fa-circle-check text-sm"></i>
                                            </>
                                        ) : userCoins >= item.price ? (
                                            <>
                                                <span>רכוש עכשיו</span>
                                                <i className="fa-solid fa-cart-shopping text-sm"></i>
                                            </>
                                        ) : (
                                            'אין מספיק מטבעות'
                                        )}
                                    </button>
                                </div>
                            </div>
                        );
                    })}
                </div>

                {/* Empty State */}
                {filteredItems.length === 0 && (
                    <div className="flex flex-col items-center justify-center py-20 text-center">
                        <i className="fa-solid fa-palette text-6xl text-dogame-muted mb-6 opacity-20"></i>
                        <h3 className="text-2xl font-bold text-white mb-2">לא נמצאו צבעים בקטגוריה זו</h3>
                        <p className="text-dogame-muted">נסה לבחור קטגוריה אחרת או לחזור ל-"הכל"</p>
                    </div>
                )}
            </div>
        </div>
    );
};

export default ShopView;

import React from 'react';
import { BackgroundItem } from '../types';

interface BackgroundCollectionModalProps {
    isOpen: boolean;
    onClose: () => void;
    ownedItems: BackgroundItem[];
    onEquip: (item: BackgroundItem) => void;
    currentEquippedUrl?: string;
}

const BackgroundCollectionModal: React.FC<BackgroundCollectionModalProps> = ({ 
    isOpen, 
    onClose, 
    ownedItems, 
    onEquip,
    currentEquippedUrl
}) => {
    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 bg-black/80 z-[100] flex justify-center items-center p-4 backdrop-blur-md" onClick={onClose}>
            <div className="bg-dogame-bg w-full max-w-4xl max-h-[80vh] relative rounded-[40px] overflow-hidden border border-white/10 shadow-2xl flex flex-col" onClick={e => e.stopPropagation()}>

                {/* Header */}
                <div className="p-8 border-b border-white/5 flex items-center justify-between shrink-0">
                    <button onClick={onClose} className="w-10 h-10 flex items-center justify-center text-white/50 hover:text-white transition-colors text-xl">
                         <i className="fa-solid fa-xmark"></i>
                    </button>
                    <div className="text-right">
                        <h2 className="text-2xl font-black text-white italic uppercase tracking-tighter">האוסף שלי</h2>
                        <p className="text-dogame-muted text-sm font-bold">בחר רקע להצגה בפרופיל שלך</p>
                    </div>
                </div>

                {/* Grid */}
                <div className="flex-1 overflow-y-auto p-8 no-scrollbar">
                    {ownedItems.length === 0 ? (
                        <div className="h-64 flex flex-col items-center justify-center text-center opacity-30">
                            <i className="fa-solid fa-store text-6xl mb-4"></i>
                            <h3 className="text-xl font-bold text-white uppercase italic">האוסף שלך ריק</h3>
                            <p className="text-sm">רכוש רקעים בחנות כדי לראות אותם כאן</p>
                        </div>
                    ) : (
                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                            {ownedItems.map((item) => {
                                const isEquipped = currentEquippedUrl === item.previewUrl;

                                return (
                                    <div key={item.id} className={`group relative rounded-3xl overflow-hidden border-2 transition-all duration-300 shadow-xl ${isEquipped ? 'border-dogame-primary' : 'border-white/5 hover:border-dogame-primary/50'}`}>
                                        <div className="aspect-video relative overflow-hidden cursor-pointer" onClick={() => onEquip(item)}>
                                            <div 
                                                style={{ background: item.previewUrl }} 
                                                className={`w-full h-full transition-transform group-hover:scale-110 ${item.isAnimated ? item.animationClass : ''}`}
                                            />
                                            <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent opacity-60"></div>

                                            {/* Rarity Tag */}
                                            <div className="absolute top-3 right-3 px-2 py-0.5 rounded-full text-[8px] font-black bg-black/50 text-white border border-white/10 uppercase italic">
                                                {item.rarity}
                                            </div>

                                            {isEquipped && (
                                                <div className="absolute inset-0 flex items-center justify-center bg-dogame-primary/20 backdrop-blur-[2px]">
                                                    <div className="bg-dogame-primary text-white text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest shadow-glow">
                                                        מיושם כעת
                                                    </div>
                                                </div>
                                            )}
                                        </div>

                                        <div className="p-4 bg-dogame-surface/50 text-right">
                                            <h4 className="text-white font-bold text-sm mb-3">{item.name}</h4>
                                            <button 
                                                onClick={() => onEquip(item)}
                                                disabled={isEquipped}
                                                className={`w-full py-2 text-[10px] font-black uppercase rounded-xl transition-colors ${
                                                    isEquipped 
                                                    ? 'bg-white/5 text-dogame-muted border border-white/10' 
                                                    : 'bg-dogame-primary text-white hover:bg-dogame-primary/80 shadow-glow'
                                                }`}
                                            >
                                                {isEquipped ? 'מיושם' : 'החל רקע'}
                                            </button>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </div>

                {/* Footer Action */}
                <div className="p-6 bg-black/20 border-t border-white/5 text-center shrink-0">
                    <p className="text-xs text-dogame-muted font-bold mb-4 italic uppercase">רוצה עוד רקעים?</p>
                    <button 
                        onClick={onClose} 
                        className="px-8 py-3 bg-white/5 text-white rounded-full font-black text-[10px] uppercase tracking-widest border border-white/10 hover:bg-white/10 transition-all"
                    >
                        חזור לחנות
                    </button>
                </div>
            </div>
        </div>
    );
};

