                                            <div className="relative w-24 h-24 p-1 rounded-full overflow-hidden">
                                                <div 
                                                    style={{ background: item.previewUrl }} 
                                                    className={`absolute inset-0 ${item.isAnimated ? item.animationClass : ''}`}
